        THIS_MUST_BE_WHAT_THEY_MEAN_WHEN_THEY                                   = 6809,  -- This must be what they mean when they say, there are many mysteries behind works of art, kupo! It's all yours, kupo!
        SOMETHING_CLATTERED_INSIDE_THE_WHEN_I_SHOOK_IT                          = 6810,  -- Something clattered inside the % when I shook it! Look what fell out when I turned it upside down, kupo!
        IT_S_ALL_YOURS_KUPO_3                                                   = 6811,  -- It's all yours, kupo!
        I_FELT_THERE_WAS_SOMETHING_STRANGE_ABOUT_THE                            = 6812,  -- I felt there was something strange about the %, and when I looked into it, I found this, kupo!
        WE_MOOGLES_HAVE_VERY_GOOD_INTUITION_KUPO_IT                             = 6813,  -- We moogles have very good intuition, kupo! It's all yours, kupo!
        OH_MASTER_YOU_WON_T_BELIEVE_WHAT_I                                      = 6814,  -- Oh, Master! You won't believe what I found out on the doorstep this morning, kupo!
