        WINDURSTTFC_A_I                                                         = 7993,  -- WindursttFC#%A=I
        THE_DOOR_IS_UNLOCKED                                                    = 7994,  -- The door is unlocked.
        THIS_IS_IT_NOW_I_CAN_FINALLY_MAKE                                       = 7995,  -- This is it! Now I can finally make some progress with my plan!
        ID_7996                                                                 = 7996,  -- !!!
        WHOA_A_CURIOUS_ONE_YOU_ARE_WHATTARU_DID                                 = 7997,  -- Whoa! A curious one, you are. Whattaru? Did you follow me all the way here?
        YOU_RE_ON_A_MISSION_FROM_THE_OPTISTERY                                  = 7998,  -- You're on a mission from the Optistery? Oh, so you're the foolhardy adventurer who accepted that one.
        DO_YOU_REALLY_THINK_THAT_THE_BOOK_OF                                    = 7999,  -- Do you really think that the Book of the Gods could actually fall into the hands of that petty thief, the Cat Burglar?
        THIS_IS_NO_BOOK_OF_THE_GODS_IT                                          = 8000,  -- This is no Book of the Gods. It's just a work of the famous Karaha-Baruha...
        WAIT_A_MINUTARU_THIS_MARK                                               = 8001,  -- Wait a minutaru... This mark...
        THE_PAGES_THEY_RE_BLANK                                                 = 8002,  -- The pages...they're blank...!
        IT_CAN_TARU_BE_THE_TIME_FOR_THE                                         = 8003,  -- It can'taru be... The time for the Book of the Gods to lose its magic has come...
        YOU_YOU_MUST_HURRY_BACK_TO_THE_OPTISTERY                                = 8004,  -- You! You must hurry back to the Optistery!
        TELL_TOSUKA_PORIKA_THAT_THE_PAGES_OF_THE                                = 8005,  -- Tell Tosuka-Porika that the pages of the Book of the Gods have turned blank. Tell him the Book of the Gods is no more!
        HAVE_YOU_SEENIVE_OFPADES                                                = 8006,  -- HaVe yoU seEnivE oFpaDes?
        HE_SAYE_WANT_BECOMEONQUEST_GUARD_HE_LEAVEINDURST                        = 8007,  -- He sAyE waNt becOmEonQueSt GuaRd! He LeaVeinDurSt!
        IHINK_HE_NOTAKE_TOO_FAR                                                 = 8008,  -- IhInK hE noTakE tOo faR!
        WELCOME_TO_THE_AUCTION_HOUSE_DO_YOU_HAVE                                = 8009,  -- Welcome to the auction house. Do you have any questions about our establishment?
        WHAT_DO_YOU_WANT_TO_KNOW_WHAT_IS_2                                      = 8010,  -- What do you want to know? What is the auction house? How are auctions run? Are there any fees? Are there any limits? How do you check up on merchandise? How do you remove an item? My Sales Status list is full! Nothing right now.
        AUCTION_HOUSES_CAN_BE_FOUND_IN_ALL_OF                                   = 8011,  -- Auction houses can be found in all of Vana'diel's major cities. Here adventurers gather to bid on battle spoils, unwanted items, old armor...almost anything.
        CURRENTLY_THE_AUCTION_HOUSES_IN_BASTOK_SAN_D                            = 8012,  -- Currently, the auction houses in Bastok, San d'Oria, Windurst, and Jeuno all work independently. Therefore, prices differ from city to city.
        ADVENTURERS_MAY_USE_ANY_AUCTION_HOUSE_REGARDLESS_OF                     = 8013,  -- Adventurers may use any auction house regardless of nationality.
        THE_FIRST_ADVENTURER_TO_BID_AT_OR_ABOVE                                 = 8014,  -- The first adventurer to bid at or above the asking price will automatically purchase the product.
        ONCE_PUT_UP_FOR_AUCTION_MERCHANDISE_WILL_REMAIN                         = 8015,  -- Once put up for auction, merchandise will remain there for a maximum of thirty weeks Vana'diel time (nine-and-a-half days Earth time).
        IF_MERCHANDISE_DOES_NOT_SELL_WITHIN_THIS_TIME                           = 8016,  -- If merchandise does not sell within this time limit, it will be returned to the seller's current residence.
        TRANSACTION_FEES_ARE_PROPORTIONAL_TO_THE_AMOUNT_FOR                     = 8017,  -- Transaction fees are proportional to the amount for which an item is put up on auction. The method of calculating this fee is different for single items and stackable items.
        A_TRANSACTION_FEE_IS_COLLECTED_WHEN_ANY_MERCHANDISE                     = 8018,  -- A transaction fee is collected when any merchandise is put up for auction. This fee is nonrefundable.
        THE_INTERNATIONAL_AUCTION_HOUSE_COMMITTEE_OR_IAHC_HAS                   = 8019,  -- The International Auction House Committee, or IAHC, has declared that a maximum of seven items may be put up for auction at one time.
        HOWEVER_THE_IAHC_HAS_RECENTLY_REMOVED_THE_LIMIT                         = 8020,  -- However, the IAHC has recently removed the limit to how many items one may purchase.
        A_SMALL_AMOUNT_OF_TIME_IS_REQUIRED_BEFORE                               = 8021,  -- A small amount of time is required before new merchandise appears on our bid list.
        ONCE_AN_ITEM_APPEARS_ON_YOUR_SALES_STATUS                               = 8022,  -- Once an item appears on your Sales Status list, it may not immediately appear on the bid list. If you do not see your item on the bid list, try looking again at a later time.
        IF_YOU_WOULD_LIKE_TO_WITHDRAW_AN_ITEM                                   = 8023,  -- If you would like to withdraw an item from an auction, you must travel to the auction house, and select Stop Sale from the Sales Status menu.
        TO_REMOVE_AN_ITEM_FROM_YOUR_SALES_STATUS                                = 8024,  -- To remove an item from your Sales Status list, you must visit an auction counter to acknowledge the sale or return of your merchandise.
        OTHERWISE_PREVIOUSLY_SOLD_OR_RETURNED_ITEMS_WILL_FILL                   = 8025,  -- Otherwise, previously sold or returned items will fill up your list and prevent you from selling any more merchandise.
        AT_ANY_AUCTION_COUNTER_OPEN_THE_SALES_STATUS                            = 8026,  -- At any auction counter, open the Sales Status menu and acknowledge the transaction to clear it from the list.
        PRESS_THE_CONFIRM_BUTTON_TO_REMOVE_ANY_TRANSACTION                      = 8027,  -- Press the confirm button to remove any transaction colored yellow (sold) or red (returned).
        IS_THERE_ANYTHING_ELSE_YOU_WOULD_LIKE_TO                                = 8028,  -- Is there anything else you would like to know?
        IN_THE_PAST_MANY_HAVE_AMASSED_GREAT_WEALTH                              = 8029,  -- In the past, many have amassed great wealth through the auction house. I hope you find fortune, too!
        YOU_RECEIVE_NOTHING_FROM_THE_MOON_RABBIT                                = 8030,  -- You receive nothing from the moon rabbit...
        THE_MOON_RABBIT_HAS_BROUGHT_ALONG_A_MONSTER                             = 8031,  -- The moon rabbit has brought along a monster!
        YOU_HAVE_TO_DO_SOMETHING_ABOUT_THOSE_CRAZY                              = 8032,  -- You have to do something about those crazy trees, kupo!
