        WHAT_WE_CALL_SERVES_TO_DISPENSE_FEWELL_CRYSTALS                         = 9932,  -- What we call % serves to dispense fewell crystals--the lifeblood of the synergy process--whilst also protecting its contents from the volatile reactions that occur within the bowels of the furnace.
        SYNERGY_FURNACES_HAVE_BEEN_INSTALLED_THROUGHOUT_THE_CITY                = 9933,  -- Synergy furnaces have been installed throughout the city for the use of all synergists. The crucible is sufficiently compact and lightweight that you can carry it with you.
