        NEEDLESS_TO_SAY_WHAT_WILL_HAPPEN_FROM_THERE                             = 9935,  -- Needless to say, what will happen from there is not quite so simple.
        SUCCESSFUL_SYNERGY_IS_CONTINGENT_UPON_MAINTAINING_ELEMENTAL_EQUILIBRIUM = 9936,  -- Successful synergy is contingent upon maintaining elemental equilibrium. The prescribed ratio, of course, will vary depending on the artifact you are attempting to create.
