        MY_FINE_LAD_YOUNG_WOMAN_YOUR_SUPPORT_OF                                 = 10167,  -- My fine lad/young woman], your support of Mumor throughout the years has meant the world to me.
        THIS_I_PROMISE_AS_DEDICATED_AS_HER_FANS                                 = 10168,  -- This I promise--as dedicated as her fans are to her, she is twice as dedicated to them.
        AND_IT_S_THANKS_TO_YOU_THAT_I                                           = 10169,  -- And it's thanks to you that I've shaken off the heebie-jeebies and am ready to face a new day!
        I_HAVE_A_SPECIAL_PLACE_IN_MY_HEART                                      = 10170,  -- I have a special place in my heart for each and every one of my fans--but especially you!
        I_VE_BEEN_WAITING_FOR_YOU_KUPO_MUMOR                                    = 10171,  -- I've been waiting for you, kupo! Mumor, the shining starlet herself, has slunk her way onto the streets to see you!
        I_M_SO_GLAD_YOU_RE_HERE_WITH                                            = 10172,  -- I'm so glad you're here! With all my singing and battling, I never seem to find the time to meet my wonderful fans!
        I_WAS_POSITIVELY_TICKLED_TO_SEE_YOU_IN                                  = 10173,  -- I was positively tickled to see you in the crowd. Can I ask your name?
        YOUR_DANCING_WAS_POSITIVELY_PEACHY_T                                    = 10174,  -- %, your dancing was positively peachy!t
        REMEMBER_HOW_DIVA_CALLED_FORTH_ANOTHER_ME                               = 10175,  -- Remember how Diva called forth another me?
