        THOUGH_I_AM_ONLY_AUTHORIZED_TO_ACCEPT_A                                 = 10433,  -- Though I am only authorized to accept a limited selection of equipment at present, the A.M.A.N. is considering making further additions to this list, so please check back regularly.
        WOULD_YOU_LIKE_RECLAMATION_MARK_IN_EXCHANGE_FOR                         = 10434,  -- Would you like # reclamation mark[/s] in exchange for one %? You currently have # mark[/s].
