        ONLY_THOSE_PARTICIPATING_IN_RECORDS_OF_EMINENCE_MAY                     = 10440,  -- Only those participating in Records of Eminence may trade in items.
        YOU_CAN_T_SHAKE_THE_FEELING_THAT_YOU                                    = 10441,  -- You can't shake the feeling that you may be able to learn about Ygnas's whereabouts somewhere in this area.
        SPEAK_WITH_PLOH_TRISHBAHK_AT_CASTLE_ADOULIN_S                           = 10442,  -- Speak with Ploh Trishbahk at Castle Adoulin's front gates (K-9) and report what you have learned about Ygnas.
        WELCOME_TO_THE_DEEDS_OF_HEROISM_REWARDS_EXCHANGE                        = 10443,  -- Welcome to the Deeds of Heroism rewards exchange service!
        WHAT_WOULD_YOU_LIKE_TO_DO_CLAIM_A                                       = 10444,  -- What would you like to do? Claim a reward (~960 deeds). Claim a reward (970+ deeds). Use an A.M.A.N. voucher. Receive a %. What are Deeds of Heroism? Leave.
        DEEDS_OF_HEROISM_ARE_SPECIAL_POINTS_YOU_CAN                             = 10445,  -- Deeds of Heroism are special points you can earn by completing the Monthly Challenges available under the "Other" menu within the Records of Eminence.
        ONCE_YOU_HAVE_ACCUMULATED_A_CERTAIN_NUMBER_OF                           = 10446,  -- Once you have accumulated a certain number of Deeds, you can exchange them for various items.
        REWARDS_THAT_REQUIRE_970_DEEDS_OR_MORE_CAN                              = 10447,  -- Rewards that require 970 deeds or more can be reset by collecting a certain amount of deeds.
        THERE_ARE_MANY_FABULOUS_ITEMS_TO_BE_HAD                                 = 10448,  -- There are many fabulous items to be had, including some that will help you on your adventures, so try to earn as many Deeds as possible!
        DO_YOU_WANT_TO_USE_AN_A_M                                               = 10449,  -- Do you want to use an A.M.A.N. voucher? %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. %. What are A.M.A.N. vouchers? Go back. Leave.
        IF_YOU_HAVE_AN_A_M_A_N                                                  = 10450,  -- If you have an A.M.A.N. voucher for an item such as a %, you can use it to choose from a list of corresponding items.
        DO_YOU_WANT_THE                                                         = 10451,  -- Do you want the %?
