        THERE_ARE_MORE_PRESSING_MATTERS_TO_WHICH_WE                             = 10832,  -- There are more pressing matters to which we must attend-- The issue of Selh'teus, to whose will the crystal shall bend.
        THIS_WORLD_OF_YOURS_TARTARUS_IT_HAS_ME                                  = 10833,  -- This world of yours--Tartarus?--it has me intrigued. Please, Shantotto, help us! I can hear you plead.
        NOW_WAIT_JUST_A_MINUTE_WHY_HAVEN_T                                      = 10834,  -- Now wait just a minute. Why haven't I heard-ethy of this Tartarus?
        DEAR_YORAN_ORAN_OF_COURSE_I_KNOW_OF                                     = 10835,  -- Dear Yoran-Oran, of course I know of this world. They want to know more, with details unfurled.
        H_HOW_DO_YOU_KNOW_OF_IT                                                 = 10836,  -- H-how do you know of it?
        VANA_DIEL_IS_IN_BUT_ONE_OF_COUNTLESS                                    = 10837,  -- Vana'diel is in but one of countless dimensions. Though blessed by Altana, I must dutifully mention.
