        THE_NAME_BY_ITSELF_IS_A_CAUSE_FOR                                       = 10839,  -- The name by itself is a cause for alarm, And doubtless there are monsters who wish to cause harm.
        DIDDLY_DOO_THE_UNIVERSE_IS_SUCH_A_BIG                                   = 10840,  -- Diddly-doo, the universe is such a big place!
        KORU_MORU_YOU_ACT_AS_IF_YOU_RE                                          = 10841,  -- Koru-Moru, you act as if you're wholly disconnected, But how soon you forget that monstrosity you've erected.
        YOU_RE_ALWAYS_INVOLVED_IN_SOME_MONKEY_BUSINESS                          = 10842,  -- You're always involved in some monkey business, And to a more sorry sight I've never borne witness.
        WHAT_DID_YOU_DO_THIS_TIME                                               = 10843,  -- What did you do this time?
