        YOU_KNOW_WHAT_I_MEAN_YOU_RE_AN                                          = 10846,  -- You know what I mean--you're an adventureeno!
        BUT_THE_FORCES_OF_LIGHT_AND_DARK_MUST                                   = 10847,  -- But the forces of light and dark must always be in balance, and one never wins out for very long.
        SO_IF_SOME_DIDDLY_DARKNESS_APPEARS_SOMEWHERE                            = 10848,  -- So if some diddly-darkness appears somewhere...
