        AND_YOU_WANT_TO_USE_THAT_THING_ETHY                                     = 10850,  -- And you want to use that thing-ethy of yours to find the evil they're on the lookout for?
        JUST_THINK_DIDDLY_INK_ABOUT_IT_WHAT_HERO                                = 10851,  -- Just think-diddly-ink about it! What hero wouldn't want to get their hands on something that could seek out evil before it strikes?
        THOUGH_I_HAD_INTENDED_TO_USE_IT_TO                                      = 10852,  -- ...Though I had intended to use it to root out cheating studentareenos...
        BUT_IT_DID_THE_STRANGE_DIDDLY_ANGEST_THING                              = 10853,  -- But it did the strange-diddly-angest thing when I brought it to life. It pointed in a really weird direction.
