        SEVERAL_IN_HEAVENS_TOWER_SEEM_TO_HAVE_MEMORY                            = 11005,  -- Several in Heavens Tower seem to have memory issues. I would shed a tear, but I'm all out of tissues.
        THERE_S_A_SINISTER_FORCE_BEHIND_ALL_OF                                  = 11006,  -- There's a sinister force behind all of this. If you could find out what's wrong, it would bring me nothing but bliss.
        SO_PLEASE_FULFILL_YOUR_CHARGE_WE_KNOW_THAT                              = 11007,  -- So, [doubtful one/dear addventurer], please fulfill your charge. We know that somewhere out there is a criminal at large.
        AND_TELL_KUPIPI_TO_PLEASE_ASSIST_WITH_THIS                              = 11008,  -- And tell Kupipi to please assist with this case. If she does, she can consider her crimes erased.
