        PLEASE_DON_T_TELL_ME_YOU_VE_FORGOTTEN                                   = 11015,  -- Please, don't tell me you've forgotten... Or it'll be more than just your memory that's rotten.
        CABOOSE_YOU_CLAIM_YES_I_SUPPOSE_THAT_SOUNDS                             = 11016,  -- Caboose, you claim? Yes, I suppose that sounds somewhat like an evil mastermind's name.
